import heapq
def minimum_effort_path(heights):
    m, n = len(heights), len(heights[0])
    INF = 10**9
    dist = [[INF]*n for _ in range(m)]
    dist[0][0] = 0
    pq = [(0, 0, 0)]
    dirs = [(1,0),(-1,0),(0,1),(0,-1)]
    while pq:
        d, r, c = heapq.heappop(pq)
        if (r, c) == (m-1, n-1):
            return d
        if d != dist[r][c]:
            continue
        for dr, dc in dirs:
            i, j = r + dr, c + dc
            if 0 <= i < m and 0 <= j < n:
                w = abs(heights[i][j] - heights[r][c])
                nd = max(d, w)
                if nd < dist[i][j]:
                    dist[i][j] = nd
                    heapq.heappush(pq, (nd, i, j))
    return -1

